// 狐妖小红娘·王权篇状态栏控制器 v1.1.0
// v1.1.0: 显示此去无归与最终抉择分支。
// scoped 正则只投放安全挂载点，本脚本以 Shadow DOM 渲染并读取挂载点所在楼层的 MVU。
const STATUSBAR_HTML = "<main class=\"card\" aria-label=\"王权篇状态栏\">\n  <header class=\"head\">\n    <div>\n      <p class=\"eyebrow\">王权篇 · 清瞳</p>\n      <h2 id=\"stage\">读取剧情阶段中…</h2>\n    </div>\n    <span id=\"affinity-badge\" class=\"badge\">好感 --</span>\n  </header>\n  <section class=\"facts\" aria-label=\"场景状态\">\n    <div class=\"fact\"><span>时间</span><strong id=\"time\">--</strong></div>\n    <div class=\"fact\"><span>地点</span><strong id=\"location\">--</strong></div>\n  </section>\n  <section class=\"status\">\n    <span>清瞳状态</span>\n    <p id=\"qing-status\">正在读取变量…</p>\n  </section>\n  <section id=\"decision-section\" class=\"decision\" hidden>\n    <span>命运抉择</span>\n    <p id=\"decision\">尚未选择</p>\n  </section>\n  <section class=\"affinity\" aria-label=\"好感度\">\n    <div class=\"affinity-row\"><span id=\"affinity-label\">疏离 / 警戒</span><strong id=\"affinity-value\">0 / 100</strong></div>\n    <div class=\"track\"><i id=\"affinity-fill\"></i></div>\n  </section>\n  <details class=\"thought\">\n    <summary>清瞳心声 <span>展开</span></summary>\n    <p id=\"thought\">……</p>\n  </details>\n</main>\n<style>\n:root{color-scheme:dark;font-family:\"Microsoft YaHei\",\"PingFang SC\",system-ui,sans-serif;color:#f5ecdf;background:transparent}\nbody{padding:6px 2px 10px;background:transparent}\n.card{width:min(100%,760px);margin:0 auto;padding:14px;border:1px solid rgba(235,193,111,.5);border-radius:16px;background:linear-gradient(145deg,rgba(34,22,38,.98),rgba(16,18,31,.98));box-shadow:0 12px 28px rgba(0,0,0,.28);overflow:hidden}\n.head{display:flex;align-items:flex-start;justify-content:space-between;gap:12px;padding-bottom:11px;border-bottom:1px solid rgba(255,255,255,.09)}\n.eyebrow{margin:0 0 4px;color:#d7aa68;font-size:11px;letter-spacing:.18em;text-transform:uppercase}\nh2{margin:0;color:#fff7e8;font-size:17px;line-height:1.35;font-weight:650;overflow-wrap:anywhere}\n.badge{flex:0 0 auto;padding:6px 9px;border:1px solid rgba(217,171,100,.48);border-radius:999px;background:rgba(217,171,100,.12);color:#f3cf91;font-size:12px;white-space:nowrap}\n.facts{display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-top:10px}\n.fact,.status,.decision,.affinity,.thought{border:1px solid rgba(255,255,255,.075);border-radius:11px;background:rgba(255,255,255,.035)}\n.fact{min-width:0;padding:9px 10px}\n.fact span,.status>span,.decision>span{display:block;margin-bottom:4px;color:#b9adbd;font-size:11px}\n.fact strong{display:block;color:#f4eadc;font-size:13px;font-weight:600;overflow-wrap:anywhere}\n.status,.decision{margin-top:8px;padding:9px 10px}\n.status p,.decision p,.thought p{margin:0;color:#ece3e7;font-size:13px;line-height:1.65;overflow-wrap:anywhere}\n.decision p{color:#f3cf91;font-weight:650}\n[hidden]{display:none!important}\n.affinity{margin-top:8px;padding:9px 10px}\n.affinity-row{display:flex;justify-content:space-between;gap:10px;margin-bottom:7px;color:#d8c8d7;font-size:12px}\n.affinity-row strong{color:#f2cf93;font-weight:650}\n.track{height:7px;border-radius:999px;background:rgba(255,255,255,.09);overflow:hidden}\n.track i{display:block;width:0;height:100%;border-radius:inherit;background:linear-gradient(90deg,#b76579,#e1b06e);transition:width .35s ease}\n.thought{margin-top:8px;padding:0 10px}\n.thought summary{padding:9px 0;color:#dacbd7;font-size:12px;cursor:pointer;list-style:none}\n.thought summary::-webkit-details-marker{display:none}\n.thought summary span{float:right;color:#a99baa}\n.thought[open] summary span{font-size:0}\n.thought[open] summary span::after{content:\"收起\";font-size:12px}\n.thought p{padding:0 0 10px;color:#cfc3cc;font-style:italic}\n@media(max-width:520px){body{padding:4px 0 8px}.card{padding:11px;border-radius:13px}.head{align-items:center}.facts{grid-template-columns:1fr}h2{font-size:15px}.badge{padding:5px 7px;font-size:11px}}\n@media(max-width:340px){.head{display:block}.badge{display:inline-block;margin-top:8px}.card{padding:9px}}\n</style>";
const MOUNT_SELECTOR = '[data-hyxhn-statusbar-mount]';
const roots = new Map();

const STAGE_NAMES = Object.freeze({
  '00_序章_道门兵人': '序章 · 道门兵人',
  '01_任务_蛛网疑影': '任务 · 蛛网疑影',
  '02_初遇_笼中清瞳': '初遇 · 笼中清瞳',
  '03_相知_画中山河': '相知 · 画中山河',
  '04_决裂_此去无归': '决裂 · 此去无归',
  '05_尾声_万水千山': '尾声 · 万水千山',
  '05_结局_无心之剑': '结局 · 无心之剑',
});

function parentDocument() {
  try { return window.parent?.document || document; } catch { return document; }
}

function getMvu() {
  try { return window.parent?.Mvu || window.Mvu || null; } catch { return window.Mvu || null; }
}

function getMessageData(messageId) {
  const mvu = getMvu();
  if (mvu) return mvu.getMvuData({ type: 'message', message_id: messageId }) || {};
  if (typeof getVariables === 'function') return getVariables({ type: 'message', message_id: messageId }) || {};
  return {};
}

function affinityName(value) {
  if (value < 20) return '疏离 / 警戒';
  if (value < 40) return '试探 / 有限合作';
  if (value < 60) return '信任 / 同伴';
  if (value < 80) return '亲近 / 牵挂';
  return '深情 / 相守';
}

function messageIdOf(mount) {
  const message = mount.closest?.('.mes');
  const raw = message?.getAttribute('mesid') ?? message?.dataset?.mesid;
  const parsed = Number(raw);
  return Number.isInteger(parsed) ? parsed : 'latest';
}

function write(root, id, value, fallback = '--') {
  const node = root.getElementById(id);
  if (node) node.textContent = value === undefined || value === null || value === '' ? fallback : String(value);
}

function render(mount, root) {
  try {
    const data = getMessageData(messageIdOf(mount));
    const stat = data.stat_data || {
      剧情: { 当前阶段: '00_序章_道门兵人', 最终抉择: '尚未选择', 时间: '暮色将临', 地点: '王权山庄·演武场' },
      清瞳: { 状态: '未正式现身，正在暗处侦察王权山庄', 好感度: 5, 心声: '王权家的兵器……最好不要惊动他。' },
    };
    const stage = _.get(stat, '剧情.当前阶段', '00_序章_道门兵人');
    const affinity = _.clamp(Math.round(Number(_.get(stat, '清瞳.好感度', 5)) || 0), 0, 100);
    const decision = _.get(stat, '剧情.最终抉择', '尚未选择');
    write(root, 'stage', STAGE_NAMES[stage] || stage);
    write(root, 'time', _.get(stat, '剧情.时间'));
    write(root, 'location', _.get(stat, '剧情.地点'));
    write(root, 'qing-status', _.get(stat, '清瞳.状态'), '暂无状态记录');
    write(root, 'decision', decision, '尚未选择');
    const decisionSection = root.getElementById('decision-section');
    if (decisionSection) decisionSection.hidden = decision === '尚未选择' && stage !== '04_决裂_此去无归';
    write(root, 'thought', _.get(stat, '清瞳.心声'), '……');
    write(root, 'affinity-label', affinityName(affinity));
    write(root, 'affinity-value', `${affinity} / 100`);
    write(root, 'affinity-badge', `好感 ${affinity}`);
    const fill = root.getElementById('affinity-fill');
    if (fill) fill.style.width = `${affinity}%`;
  } catch (error) {
    write(root, 'stage', '状态栏暂未就绪');
    write(root, 'qing-status', error?.message, '请确认 MVU 已启用');
  }
}

function mountOne(mount) {
  if (roots.has(mount)) return;
  const root = mount.shadowRoot || mount.attachShadow({ mode: 'open' });
  root.innerHTML = STATUSBAR_HTML;
  roots.set(mount, root);
  render(mount, root);
}

function scan() {
  const doc = parentDocument();
  doc.querySelectorAll(MOUNT_SELECTOR).forEach(mountOne);
  for (const [mount] of roots) {
    if (!mount.isConnected) roots.delete(mount);
  }
}

function renderAll() {
  scan();
  for (const [mount, root] of roots) render(mount, root);
}

function initialize() {
  const doc = parentDocument();
  scan();
  const observer = new MutationObserver(scan);
  observer.observe(doc.body, { childList: true, subtree: true });
  $(window).on('pagehide', () => observer.disconnect());
  if (typeof waitGlobalInitialized === 'function') {
    waitGlobalInitialized('Mvu').then(() => {
      renderAll();
      const mvu = getMvu();
      if (typeof eventOn === 'function' && mvu?.events?.VARIABLE_UPDATE_ENDED) {
        eventOn(mvu.events.VARIABLE_UPDATE_ENDED, renderAll);
      }
    }).catch(error => console.warn('[王权篇状态栏] MVU 初始化等待失败，继续使用楼层变量。', error));
  }
}

$(initialize);

export {};
